from _lib import enrich

# ── 隋朝 ──────────────────────────────────────────────────────────────────────
enrich(
    "sui.json",
    person_content={
        "yang-jian": "杨坚（541—604年），弘农华阴人，隋朝开国皇帝（隋文帝）。北周外戚，581年代周建隋，589年灭陈，结束自西晋末年以来近三百年的分裂，重新统一中国。在位期间开创三省六部制、确立科举雏形、行均田与租庸调、改定律令、统一货币度量衡，励精图治、轻徭薄赋，国富民殷，史称「开皇之治」，奠定隋唐盛世的制度根基。",
        "du-gu-huang-luo": "独孤伽罗（544—602年），隋文帝皇后，名门独孤信之女。与文帝感情笃厚、共理朝政，时称「二圣」。性强毅而有识见，参预军国大事，力主节俭、不蓄声色，但善妒专断，干预立储，废太子杨勇而立杨广，对隋朝政局影响深远。",
        "yang-guang": "杨广（569—618年），隋朝第二位皇帝（隋炀帝）。早年灭陈有功、夺嫡即位。在位营建东都洛阳、开凿大运河、确立进士科、西巡张掖、通使西域，颇有雄图。然好大喜功、穷奢极欲，三征高句丽劳民伤财，徭役繁重激起天下大乱，最终在江都被部将宇文化及缢杀，隋朝二世而亡，是功过两极的争议帝王。",
        "yang-su": "杨素（544—606年），字处道，弘农华阴人，隋朝名将、权臣。文武兼资，灭陈之役为行军元帅，又平江南叛乱、击突厥，战功赫赫。善揣上意，助杨广夺嫡登基，位极人臣，权倾朝野，封楚国公，是隋初最显赫的军政重臣。",
        "han-qin-hu": "韩擒虎（538—592年），字子通，河南东垣人，隋朝名将。骁勇善射、胆略过人。589年灭陈之战为先锋，率轻骑五百夜渡长江、直入建康，俘获陈后主于枯井，居灭陈首功，与贺若弼齐名。民间传说其死后为阴司之主。",
        "he-ruo-bi": "贺若弼（544—607年），字辅伯，河南洛阳人，隋朝名将。智勇兼备，灭陈之役与韩擒虎分道并进，于钟山大破陈军主力，攻入建康，与韩擒虎同为灭陈头功。后恃功负气、口出怨言，为隋炀帝所忌，终被诛杀。",
        "li-chun-feng": "李春（生卒不详），隋朝杰出工匠、桥梁工程师。设计建造赵州桥（安济桥），采用单孔敞肩圆弧拱结构，跨度大、用料省、坚固耐久，历经千余年地震洪水而屹立不倒，是世界上现存最古老、保存最完整的敞肩石拱桥，比欧洲同类桥梁早七百余年。",
        "wang-tong": "王通（584—617年），字仲淹，绛州龙门人，隋朝大儒，门人私谥「文中子」。隐居河汾讲学，主张三教合一、王道仁政，著《中说》（《文中子》）。门下据传有房玄龄、魏征、李靖等唐初名臣，对唐代政治与学术影响深远，其弟王绩、孙王勃皆有文名。",
        "li-mi": "李密（582—619年），字玄邃，京兆长安人，隋末瓦岗军首领。出身贵族，曾参与杨玄感起兵，失败后投瓦岗。智略过人，败张须陀、破洛口仓、开仓济民，众至数十万，威震中原，一度为反隋盟主。后与王世充交战失利，降唐又叛，被唐军所杀，功败垂成。",
        "li-yuan": "李渊（566—635年），字叔德，陇西成纪人，唐朝开国皇帝（唐高祖）。隋朝唐国公、太原留守。617年乘隋末大乱于太原起兵，南下攻取长安，次年代隋称帝，建立唐朝。在位削平群雄、统一全国，奠定唐朝基业。玄武门之变后传位次子李世民，退为太上皇。",
    },
)

# ── 唐朝 ──────────────────────────────────────────────────────────────────────
enrich(
    "tang.json",
    person_content={
        "li-yuan-tang": "李渊（566—635年），字叔德，陇西成纪人，唐朝开国皇帝（唐高祖）。隋朝唐国公、太原留守。617年乘隋末大乱起兵太原，南下取长安，次年代隋建唐。在位削平群雄、统一天下，确立租庸调与府兵之制。玄武门之变后传位李世民，退为太上皇。",
        "li-shi-min": "李世民（598—649年），唐朝第二位皇帝（唐太宗）。少年从父起兵，平刘武周、败窦建德、降王世充，开国首功。626年发动玄武门之变即位。在位以隋亡为鉴，虚怀纳谏、知人善任，房谋杜断、魏征直谏，轻徭薄赋、修明政治，又灭东突厥、定西域，被各族尊为「天可汗」，开创「贞观之治」，是中国历史上最杰出的帝王之一。",
        "xuan-zang": "玄奘（602—664年），俗姓陈名祎，洛州缑氏人，唐代高僧、翻译家、旅行家。为求佛法真义，627年只身西行，历经五万里、十七年，遍学天竺诸寺，于那烂陀寺声名远播。携经像归国后主持译场，译出佛经七十五部一千三百余卷，开创法相唯识宗。口述《大唐西域记》，为研究中亚、南亚史地之瑰宝，亦是《西游记》原型。",
        "wei-zheng": "魏征（580—643年），字玄成，巨鹿人，唐太宗名臣。早年事李密、太子建成，玄武门之变后为太宗所重。以直言敢谏著称，前后陈谏二百余事，常犯颜逆鳞而太宗多能纳之。著名进谏有《谏太宗十思疏》。其死，太宗叹「以人为镜，可以明得失……今魏征殂逝，遂亡一镜矣」，为贞观之治的象征人物。",
        "fang-xuan-ling": "房玄龄（579—648年），字乔，齐州临淄人，唐太宗首席宰相。早年即随秦王，玄武门之变的主要谋划者。任相二十余年，明达政事、孜孜奉国，善谋断、能容人，与杜如晦配合无间，时称「房谋杜断」，又主持修定律令、监修国史，是贞观盛世的主要缔造者之一。",
        "li-jing-tang": "李靖（571—649年），字药师，京兆三原人，唐朝开国名将、军事家。用兵如神、谋略深远。南平萧铣、辅公祏，定江南；北破东突厥、生擒颉利可汗，西灭吐谷浑，战功赫赫，封卫国公。著兵书传世（后人辑《李卫公问对》），与药师之名并传，是后世推崇的军事家典范。",
        "wu-ze-tian": "武则天（624—705年），名曌，并州文水人，中国历史上唯一的女皇帝。初为太宗才人，后立为高宗皇后，参决朝政，与高宗并称「二圣」。690年改唐为周，自称圣神皇帝，定都洛阳。在位发展科举、开殿试武举、打击门阀、奖拔寒俊，知人善任如狄仁杰，上承贞观、下启开元。晚年「神龙政变」被迫退位，留无字碑任后人评说。",
        "li-long-ji": "李隆基（685—762年），唐朝第七位皇帝（唐玄宗）。诛韦后、平太平公主而登基。前期任用姚崇、宋璟、张说等贤相，励精图治、整顿吏治、兴修水利，开创「开元盛世」，唐朝臻于极盛。后期怠政享乐，宠杨贵妃、信李林甫杨国忠、纵安禄山掌兵，755年爆发安史之乱，仓皇幸蜀，马嵬兵变后退为太上皇，盛唐由此转衰。",
        "yang-yu-huan": "杨玉环（719—756年），蒲州永乐人，唐玄宗贵妃，中国古代四大美女之一，有「羞花」之貌。通晓音律、善歌舞，与玄宗情深，「三千宠爱在一身」，杨氏一门因之显贵。安史之乱起，玄宗奔蜀，途经马嵬坡禁军哗变，迫赐其自缢，年三十八。白居易《长恨歌》使其爱情悲剧传诵千古。",
        "li-bai": "李白（701—762年），字太白，号青莲居士，唐代最伟大的浪漫主义诗人，被尊为「诗仙」。少有逸才、仗剑远游，曾供奉翰林、力士脱靴，旋赐金放还。诗风豪放飘逸、想象奇绝、清新自然，《将进酒》《蜀道难》《望庐山瀑布》等千古传诵。一生纵酒任侠、傲岸不羁，与杜甫并称「李杜」，是盛唐气象的化身。",
        "du-fu": "杜甫（712—770年），字子美，自号少陵野老，唐代最伟大的现实主义诗人，被尊为「诗圣」，其诗被称「诗史」。一生坎坷，历经安史之乱，目睹民生疾苦。诗风沉郁顿挫、忧国忧民，《三吏》《三别》《春望》《茅屋为秋风所破歌》深刻反映时代苦难。集前代之大成，律诗尤工，与李白并称「李杜」。",
        "an-lu-shan": "安禄山（703—757年），营州柳城人，粟特、突厥混血，安史之乱祸首。善逢迎、贿赂权贵，深得玄宗与杨贵妃宠信，身兼平卢、范阳、河东三镇节度使，握重兵于北边。755年以诛杨国忠为名起兵反唐，攻陷洛阳、长安，称大燕皇帝。后目盲多疑、性情暴虐，为其子安庆绪所弑。",
        "guo-zi-yi": "郭子仪（697—781年），华州郑县人，唐朝中兴名将。安史之乱起，率朔方军勤王，收复河北、两京，为平叛首功。一生事四朝、平叛御边，曾单骑赴回纥大营退兵，威望素著。功盖天下而主不疑、位极人臣而众不忌，富贵寿考、子孙满堂，被誉为「五福俱全」「权倾天下而朝不忌」的典范。",
        "yan-zhen-qing": "颜真卿（709—785年），字清臣，京兆万年人，唐代大书法家、忠臣，楷书四大家之一。所创「颜体」雄浑端庄、气势磅礴，《多宝塔碑》《颜勤礼碑》及行书《祭侄文稿》（天下第二行书）皆为传世名作。为官刚正，安史之乱中起兵抗叛。后奉命招谕叛将李希烈，凛然不屈、骂贼而死，忠义与书艺并垂青史。",
        "han-yu": "韩愈（768—824年），字退之，河南河阳人，自称郡望昌黎，唐代文学家、思想家，「唐宋八大家」之首。倡导古文运动，反对浮华骈文，主张「文以载道」「惟陈言之务去」，文风雄健。力辟佛老、尊崇儒学，曾谏迎佛骨而贬潮州。诗文俱佳，《师说》《进学解》《祭十二郎文》传世，苏轼誉其「文起八代之衰」。",
        "bai-ju-yi": "白居易（772—846年），字乐天，号香山居士，唐代大诗人。与元稹倡新乐府运动，主张「文章合为时而著，歌诗合为事而作」，作《新乐府》《秦中吟》讽喻时弊。诗语通俗平易，「老妪能解」，《长恨歌》《琵琶行》缠绵悲婉、传诵千古。历仕多朝，晚年闲居洛阳，存诗近三千首，为唐代存诗最多的诗人。",
        "huang-chao": "黄巢（820—884年），曹州冤句人，唐末农民起义领袖。私盐贩出身，屡试不第。875年响应王仙芝起兵，后独领义军，转战大江南北，流动作战数千里。880年攻入长安，称帝建「大齐」，沉重打击唐朝统治与门阀士族。后为唐军与降将所败，退出长安，兵败自杀。其乱使唐朝名存实亡。",
        "zhu-wen": "朱温（852—912年），宋州砀山人，五代后梁开国皇帝（梁太祖）。原为黄巢部将，降唐赐名全忠，任宣武节度使，渐成最强藩镇。挟持唐帝、尽诛朝臣（白马驿之祸）。907年代唐称帝，建后梁，唐朝灭亡，五代十国开始。在位虽有整顿之举，然性残暴猜忌，后为子朱友珪所弑。",
    },
)

# ── 北宋 ──────────────────────────────────────────────────────────────────────
enrich(
    "bei-song.json",
    person_content={
        "zhao-kuang-yin-bs": "赵匡胤（927—976年），涿州人，北宋开国皇帝（宋太祖）。后周禁军统帅，屡立战功。960年陈桥兵变、黄袍加身，代周建宋。即位后行「杯酒释兵权」，收兵权于中央，确立崇文抑武、强干弱枝之策。先南后北，次第削平诸国，结束五代十国分裂，奠定北宋一统与文治格局。",
        "zhao-guang-yi": "赵光义（939—997年），宋太宗，太祖弟。976年即位，979年灭北汉，完成统一。然高梁河之战大败于辽，从此北宋对辽转为守势。扩大科举取士、编纂《太平御览》《文苑英华》等大型类书，崇文之风大盛。在位期间确立「重文轻武」国策，影响北宋三百年。",
        "zhao-heng": "赵恒（968—1022年），宋真宗，太宗子。1004年辽军南侵，真宗御驾亲征至澶州，与辽订立「澶渊之盟」，以岁币换和平，开创宋辽百年和局。在位后期崇信道教、东封西祀，耗费国帑。真宗朝名相辈出，如寇准、王旦等。",
        "zhao-zhen": "赵祯（1010—1063年），宋仁宗，真宗子。在位四十二年，为北宋在位最久之君。性宽厚仁慈，虚心纳谏，朝堂名臣荟萃：范仲淹、欧阳修、包拯、韩琦、富弼等。庆历新政虽夭折，但文治鼎盛，为「仁宗盛治」。仁宗驾崩，「京师罢市巷哭，数日不绝」，足见深得民心。",
        "zhao-xu": "赵顼（1048—1085年），宋神宗，仁宗侄孙。锐意图治，1069年起用王安石推行变法（熙宁变法），涉及青苗、免役、市易、保甲诸法，旨在富国强兵。然新旧党争激烈，变法屡遭阻挠。元丰年间又行官制改革（元丰改制）。神宗壮志未酬，三十八岁英年早逝，此后北宋党争愈烈。",
        "kou-zhun": "寇准（961—1023年），字平仲，华州下邽人，北宋名相。刚直敢言，太宗朝即以直谏著称。1004年辽军大举南侵，朝中主和主战两派争执，寇准力排众议、坚请真宗亲征澶州，促成「澶渊之盟」，稳定北宋局势。后遭丁谓构陷，贬死雷州，天下冤之。",
        "fan-zhong-yan": "范仲淹（989—1052年），字希文，苏州吴县人，北宋名臣、文学家。少孤贫力学，划粥断齑。1043年主持「庆历新政」，提出明黜陟、抑侥幸等十事，虽因保守派反对而夭折，开王安石变法之先声。文学上工诗词散文，《岳阳楼记》「先天下之忧而忧，后天下之乐而乐」传诵千古，为士大夫精神之典范。",
        "ou-yang-xiu": "欧阳修（1007—1072年），字永叔，号醉翁、六一居士，吉州永丰人，北宋文坛盟主、「唐宋八大家」之一。倡导古文运动，文风平易流畅，一洗西昆体绮靡之风。任谏官时支持范仲淹新政，后因直言屡遭贬谪。主持编纂《新唐书》《新五代史》，又有《醉翁亭记》《秋声赋》等名篇传世。苏轼、曾巩、王安石皆出其门下。",
        "wang-an-shi": "王安石（1021—1086年），字介甫，号半山，抚州临川人，北宋改革家、文学家。1069年拜相推行「熙宁变法」（新法），涉及青苗法、免役法、市易法、方田均税法等，旨在富国强兵、抑制兼并。新法触动既得利益，遭司马光等旧党激烈反对，两党相争贯穿北宋后期。变法虽成效争议极大，但其改革精神影响深远。文学上为「唐宋八大家」之一。",
        "si-ma-guang": "司马光（1019—1086年），字君实，号迂夫，陕州夏县人，北宋政治家、史学家。以砸缸故事闻名，历仕四朝。反对王安石变法，退居洛阳十五年主编《资治通鉴》，编年体通史巨著，记载战国至五代一千三百六十二年史事，与《史记》并称「史学双璧」。哲宗初年拜相，尽废新法，新旧党争白热化。",
        "su-shi": "苏轼（1037—1101年），字子瞻，号东坡居士，眉州眉山人，北宋最杰出的文学家、「唐宋八大家」之一。诗词文赋书画无一不精，词开豪放一派，《念奴娇·赤壁怀古》《水调歌头·明月几时有》千古传诵。一生仕途坎坷，因乌台诗案险些丧命，屡遭贬谪（黄州、惠州、儋州），然旷达乐观，为后世文人之精神偶像。",
        "su-zhe": "苏辙（1039—1112年），字子由，号颍滨遗老，眉州眉山人，苏轼之弟，「唐宋八大家」之一。散文汪洋澹泊，政论直言敢谏。与兄轼情深谊厚，一生患难与共。仕途亦随兄起伏，屡遭贬谪。晚年闭门著述，有《栾城集》传世。",
        "di-qing": "狄青（1008—1057年），字汉臣，汾州西河人，北宋名将。出身行伍，面有刺字（黥面），勇猛善战，屡立战功。1052年率军南征，夜袭昆仑关，平定侬智高叛乱，名震天下。以武人身份官至枢密使，遭文臣猜忌，郁郁而终。其面刺双翼（涅刺）的故事广为流传。",
        "yue-fei-bs": "岳飞（1103—1142年），字鹏举，相州汤阴人，南宋抗金名将、民族英雄。少负气节，从军抗金。统率岳家军纪律严明、战力强悍，「冻死不拆屋，饿死不掳掠」。郾城大捷、朱仙镇大捷，收复襄阳六郡，金人叹「撼山易，撼岳家军难」。正当直捣黄龙之际，被十二道金牌召回。秦桧以「莫须有」罪名将其下狱，与子岳云、部将张宪同被害于风波亭，年仅三十九。孝宗即位平反，追谥「武穆」，后追封鄂王。",
        "qin-hui": "秦桧（1090—1155年），字会之，江宁人，南宋初年宰相，中国历史上最著名的奸臣之一。靖康之变中被俘北去，后南归。力主对金议和，劝高宗收诸将兵权，与金签订「绍兴和议」，向金称臣纳贡。以「莫须有」罪名害死岳飞，堵塞言路、排斥异己，把持朝政十九年。死后谥「缪丑」，后世铸铁像跪于岳飞墓前，遗臭万年。",
        "li-king-zhao": "李清照（1084—1155年），号易安居士，济南章丘人，宋代最杰出的女词人，婉约派代表。早年生活优裕，词风清新明丽，如《如梦令》「争渡，争渡，惊起一滩鸥鹭」。金兵南侵后，丈夫赵明诚病逝，颠沛流离，词风转为沉哀凄婉，《声声慢》「寻寻觅觅，冷冷清清」写尽国破家亡之痛。工诗善文，有「千古第一才女」之称。",
        "zhao-gou": "赵构（1107—1187年），宋高宗，徽宗第九子。靖康之变后即位于南京（商丘），建立南宋。南渡后定都临安（杭州），重用秦桧，以「莫须有」罪名杀岳飞，向金称臣纳贡，签订「绍兴和议」，偏安江南。在位三十六年后禅位于养子赵昚（孝宗），退居德寿宫二十余年。书法造诣极高，为南宋诸帝之最。",
    },
)

# ── 南宋 ──────────────────────────────────────────────────────────────────────
enrich(
    "nan-song.json",
    person_content={
        "zhao-gou-ns": "赵构（1107—1187年），宋高宗，徽宗第九子。靖康之变后即位于南京（商丘），建立南宋。南渡后定都临安（杭州），重用秦桧，以「莫须有」罪名杀岳飞，向金称臣纳贡，签订「绍兴和议」，偏安江南。在位三十六年后禅位于养子赵昚（孝宗），退居德寿宫二十余年。书法造诣极高，为南宋诸帝之最。",
        "qin-hui-ns": "秦桧（1090—1155年），字会之，江宁人，南宋初年宰相，中国历史上最著名的奸臣之一。靖康之变中被俘北去，后南归。力主对金议和，劝高宗收诸将兵权，与金签订「绍兴和议」，向金称臣纳贡。以「莫须有」罪名害死岳飞，堵塞言路、排斥异己，把持朝政十九年。死后铸铁像跪于岳飞墓前，遗臭万年。",
        "yue-fei-ns": "岳飞（1103—1142年），字鹏举，相州汤阴人，南宋抗金名将、民族英雄。少负气节，从军抗金。统率岳家军纪律严明、战力强悍，「冻死不拆屋，饿死不掳掠」。郾城大捷、朱仙镇大捷，收复襄阳六郡，金人叹「撼山易，撼岳家军难」。正当直捣黄龙之际，被十二道金牌召回。秦桧以「莫须有」罪名将其下狱，与子岳云、部将张宪同被害于风波亭，年仅三十九。",
        "han-shi-zhong": "韩世忠（1090—1151年），字良臣，延安人，南宋抗金名将，与岳飞、张俊、刘光世并称「中兴四将」。出身行伍，勇冠三军。黄天荡之战以八千兵围困金兀术十万大军四十八日，虽功败垂成，但威震天下。晚年反对和议、为岳飞鸣冤，杜门谢客，自号「清凉居士」，悠游而终。",
        "liang-hong-yu": "梁红玉（？—1135年），京口（今镇江）人，南宋女将，韩世忠之妻。出身武将之家，精通武艺。黄天荡之战中亲自擂鼓助战，指挥宋军围困金兵，「擂鼓战金山」传为千古佳话。后随韩世忠转战各地，封安国夫人，是中国历史上著名的巾帼英雄。",
        "xin-qi-ji": "辛弃疾（1140—1207年），字幼安，号稼轩，历城人，南宋最伟大的豪放派词人，与苏轼并称「苏辛」。少年时即参加抗金义军，南归后力主北伐，然不受重用，壮志难酬。词风豪迈奔放、慷慨激昂，《破阵子·为陈同甫赋壮词以寄之》《永遇乐·京口北固亭怀古》等名篇，充满收复故土的爱国情怀。一生以气节自负、以功业自许，却报国无门，郁郁而终。",
        "lu-you": "陆游（1125—1210年），字务观，号放翁，越州山阴人，南宋最伟大的爱国诗人。一生力主抗金，屡遭主和派打压。存诗近万首，题材广泛，爱国诗尤慷慨激昂，《书愤》《示儿》等传诵不衰。临终作《示儿》：「王师北定中原日，家祭无忘告乃翁」，至死不忘恢复中原，令人动容。",
        "zhu-xi": "朱熹（1130—1200年），字元晦，号晦庵，徽州婺源人，南宋理学集大成者，「程朱理学」的代表人物。继承发展二程学说，建立完整的理学体系，注释《四书章句集注》，成为后世科举标准教材，影响中国思想界七百余年。主持白鹿洞书院，制定《白鹿洞书院揭示》，为后世书院典范。其学说亦传入朝鲜、日本，影响深远。",
        "lu-jiu-yuan": "陆九渊（1139—1193年），字子静，号象山，抚州金溪人，南宋哲学家，心学创始人。主张「心即理」「宇宙便是吾心，吾心即是宇宙」，与朱熹的理学分庭抗礼。1175年鹅湖之会，与朱熹激辩论学，成为中国思想史上的重要事件。其心学思想后为明代王阳明继承发展，形成「陆王心学」。",
        "wen-tian-xiang": "文天祥（1236—1283年），字宋瑞，号文山，吉州庐陵人，南宋末年宰相、民族英雄。1275年元军南侵，散尽家财起兵勤王。1278年兵败被俘，元廷威逼利诱，始终不屈，作《正气歌》《过零丁洋》以明志，「人生自古谁无死，留取丹心照汗青」传诵千古。1283年从容就义于大都，年四十七。",
        "lu-xiu-fu": "陆秀夫（1236—1279年），字君实，楚州盐城人，南宋末年宰相。崖山之战（1279年）宋军战败，陆秀夫知大势已去，先驱妻子入海，后背负八岁的小皇帝赵昺投海殉国，从容赴死，南宋灭亡。与文天祥、张世杰并称「宋末三杰」。",
        "zhang-shi-jie": "张世杰（？—1279年），涿州范阳人，南宋末年名将。拥立赵昰、赵昺为帝，坚持抗元。崖山之战统帅宋军，兵败后率十余船突围，遇风暴溺死。与文天祥、陆秀夫并称「宋末三杰」，忠义之名千古流传。",
        "cheng-ji-si-han": "成吉思汗（1162—1227年），名铁木真，蒙古乞颜部人，蒙古帝国创建者。统一蒙古各部，1206年被推为大汗。此后发动大规模西征，征服中亚、西亚、东欧大片领土，建立横跨欧亚的庞大帝国。其军事才能和征服伟业改变了世界历史进程，但也伴随着巨大的杀戮和破坏。1227年灭西夏途中病逝。",
        "hu-bi-lie": "忽必烈（1215—1294年），成吉思汗之孙，拖雷之子，元朝开国皇帝（元世祖）。1260年即大汗位，1271年改国号为大元，定都大都（北京）。1279年灭南宋，统一全国，结束自唐末以来数百年的分裂。在位推行汉法、建立行省制度、开通大运河、发展海外贸易。然征日本、征安南等远征劳民伤财，晚年政局渐衰。",
    },
)

# ── 明朝 ──────────────────────────────────────────────────────────────────────
enrich(
    "ming.json",
    person_content={
        "zhu-yuan-zhang-ming": "朱元璋（1298—1398年），字国瑞，濠州钟离人，明朝开国皇帝（明太祖）。出身赤贫，幼丧父母，曾为皇觉寺僧。元末投红巾军，逐步崛起，击败陈友谅、张士诚等割据势力，1368年于应天（南京）称帝，北伐推翻元朝，统一天下。在位严刑峻法、废除丞相、大兴文字狱、实行卫所制与海禁。虽恢复经济、澄清吏治，但杀戮功臣之酷烈为历代罕见，胡惟庸案、蓝玉案牵连数万人。",
        "zhu-di": "朱棣（1360—1424年），明成祖，朱元璋第四子。封燕王于北平，1399年发动「靖难之役」，历时四年夺取侄儿建文帝之位。在位迁都北京、营建紫禁城，派郑和七下西洋，编纂《永乐大典》，五征漠北，文治武功极盛。然夺位后大肆诛戮建文旧臣，方孝孺被灭十族，手段残酷。1424年第五次北征途中病逝于榆木川。",
        "zhu-gao-chi": "朱高炽（1378—1425年），明仁宗，成祖长子。在位仅十个月即病逝，然即位后立即纠正永乐朝弊政，平反冤案、减免赋税、与民休息，开「仁宣之治」之端。体态肥胖、足有疾，不为成祖所喜，赖群臣力保得立。虽在位极短，其宽仁之政为后世称道。",
        "zhu-zhan-ji": "朱瞻基（1399—1435年），明宣宗，仁宗长子。在位十年，延续仁宗宽仁之政，政治清明、经济繁荣，史称「仁宣之治」，为明代黄金时期。善书画，尤工花鸟虫草，有「宣德炉」之雅好。又好促织（斗蟋蟀），民间戏称「促织天子」。",
        "zhu-qi-zhen": "朱祁镇（1427—1464年），明英宗，宣宗长子。1449年御驾亲征瓦剌，于土木堡全军覆没，被俘北去，史称「土木堡之变」。其弟朱祁钰即位（景泰帝），英宗被释回后幽禁于南宫七年。1457年发动「夺门之变」复辟，杀于谦。前后在位共二十二年，经历极为传奇。",
        "zhu-qi-yu": "朱祁钰（1428—1457年），明代宗（景泰帝），英宗弟。土木堡之变后即位，用于谦为兵部尚书，取得北京保卫战胜利，挽救明朝于危亡。英宗回京后将其幽禁。1457年英宗复辟后被废为郕王，旋即暴死（疑被害），死后连帝号都被剥夺，直到南明才恢复。",
        "liu-jin": "刘瑾（1451—1510年），陕西兴平人，明武宗朝权宦。本姓谈，幼年入宫，深得武宗宠信，掌司礼监，权倾朝野，时称「立皇帝」（武宗为「坐皇帝」）。擅权期间大肆敛财、排斥异己、残害忠良。1510年被揭发谋反，凌迟处死，抄出黄金白银无数。",
        "yan-song": "严嵩（1480—1567年），字惟中，号介溪，江西分宜人，明嘉靖朝内阁首辅，著名奸臣。善写青词（道教祭文），以此获嘉靖帝宠信，把持朝政二十年。与其子严世蕃贪赃枉法、卖官鬻爵、陷害忠良（如沈炼、杨继盛）。后失宠被抄家，晚年寄食墓舍而死。",
        "hai-rui": "海瑞（1514—1587年），字汝贤，号刚峰，海南琼山人，明朝著名清官。为官刚正不阿、清廉自守，人称「海青天」。任淳安知县时严拒权贵需索，抬棺上疏痛斥嘉靖帝（《治安疏》），直声震天下。万历朝复出，官至南京右都御史。一生清贫，死时仅留葛帏敝籯，丧资赖同僚凑集。",
        "qi-ji-guang": "戚继光（1528—1588年），字元敬，号南塘，山东蓬莱人，明朝抗倭名将、民族英雄。招募义乌矿工组建「戚家军」，创「鸳鸯阵」法，转战浙闽，荡平倭患，与俞大猷并称「俞龙戚虎」。后调镇蓟门，修长城、练边军，北疆安宁。著有《纪效新书》《练兵实纪》，为后世兵家经典。一代名将，晚年凄凉，贫病而终。",
        "yu-da-you": "俞大猷（1503—1579年），字志辅，号虚江，福建晋江人，明朝抗倭名将。精通剑术与棍法，尤善用大车阵。与戚继光并肩抗倭，转战东南沿海，平定倭患。又北御俺答、南征安南，一生战功卓著。为人正直耿介，不善逢迎，仕途坎坷，与戚继光并称「俞龙戚虎」。",
        "zheng-he": "郑和（1371—1433年），本姓马，小字三保，云南昆阳人，回族，明代伟大航海家。靖难之役中有功，赐姓郑。1405年至1433年间七次奉命下西洋，率领当时世界最庞大的舰队，远达东南亚、印度洋、波斯湾、红海及非洲东海岸，比哥伦布早八十余年。其航海壮举促进了中外交流，是世界航海史上的里程碑。",
        "li-shi-zhen": "李时珍（1518—1593年），字东璧，号濒湖，湖北蕲春人，明代伟大医学家、药学家。历时二十七年，三易其稿，著成《本草纲目》，收药一千八百九十二种、附方一万一千余则，图文并茂，是中国古代药学集大成之作，达尔文称之为「中国古代百科全书」。",
        "song-ying-xing": "宋应星（1587—约1666年），字长庚，江西奉新人，明末杰出科学家。1637年著成《天工开物》，分十八卷，系统记录农业、手工业生产技术，涵盖纺织、染色、制盐、制糖、陶瓷、冶炼、兵器等，附精美插图，是中国古代科技百科全书，被誉为「中国17世纪的工艺百科全书」。",
        "xu-xia-ke": "徐霞客（1587—1641年），名弘祖，字振之，号霞客，江苏江阴人，明代杰出地理学家、旅行家。二十二岁起游历天下，足迹遍及今二十一个省市，历时三十余年。所著《徐霞客游记》六十余万字，详细记述山川地貌、水文地质、风土人情，是世界上最早记述岩溶地貌的地理学巨著。",
        "wang-yang-ming": "王阳明（1472—1529年），名守仁，字伯安，号阳明，浙江余姚人，明代最伟大的哲学家、军事家，心学集大成者。龙场悟道，提出「知行合一」「致良知」学说，与朱熹理学分庭抗礼，影响中国、日本、韩国思想界五百年。军事上平定宁王朱宸濠叛乱、征讨南方匪患，文武双全。其思想至今仍具深远影响力。",
        "zhang-ju-zheng": "张居正（1525—1582年），字叔大，号太岳，湖北江陵人，明朝最杰出的政治家、改革家。万历初年内阁首辅，推行「万历新政」：考成法整顿吏治、清丈田亩、推行「一条鞭法」简化税制，国库充盈、边疆安宁。然改革触动权贵利益，死后被清算抄家，改革成果付诸东流。",
        "li-zi-cheng": "李自成（1606—1645年），陕西米脂人，明末农民起义领袖。原为驿卒，崇祯初年参加高迎祥起义军，后继为闯王。1644年攻占西安，建大顺政权，同年攻入北京，崇祯帝自缢煤山，明朝灭亡。然进京后骄奢腐败、追赃助饷，激怒吴三桂，引清兵入关，兵败一片石，退出北京，后于湖北九宫山遇害。",
        "zhu-you-jian": "朱由检（1611—1644年），明思宗（崇祯帝），光宗第五子。即位后铲除魏忠贤阉党，勤于政事、励精图治，然性格多疑、刚愎自用，频繁更换大臣，朝政混乱。内有李自成、张献忠起义，外有后金（清）步步紧逼，国势日蹙。1644年李自成攻入北京，崇祯帝于煤山（景山）自缢殉国，明朝灭亡。遗诏「任贼分裂朕尸，勿伤百姓一人」。",
    },
)

# ── 清朝 ──────────────────────────────────────────────────────────────────────
enrich(
    "qing.json",
    person_content={
        "nu-er-ha-chi": "努尔哈赤（1559—1626年），爱新觉罗氏，后金建立者。统一女真各部，1616年建立后金，创立八旗制度。1619年萨尔浒之战以少胜多大败明军，奠定后金崛起之势。后宁远之战被袁崇焕炮火击伤，不久病逝。其雄才大略为清朝入主中原奠基。",
        "huang-tai-ji": "皇太极（1592—1643年），努尔哈赤第八子，清朝开国皇帝（清太宗）。1626年继位，改女真为满洲，1636年改国号为大清。征服朝鲜、蒙古察哈尔，多次入关侵明。在位仿明制设六部、开科取士、编译汉文典籍，为入关做准备。1643年暴卒，未及入关即去世。",
        "duo-er-gun": "多尔衮（1612—1650年），努尔哈赤第十四子，清初摄政王。皇太极死后拥立幼帝福临（顺治），自任摄政王，实际掌控朝政。1644年率清军入关，定都北京，南下消灭李自成、张献忠及南明诸政权，奠定清朝统治。权势熏天，自称「皇父摄政王」，死后被追削封号。",
        "xuan-ye": "玄烨（1654—1722年），清圣祖（康熙帝），清朝第四位皇帝，八岁即位，在位六十一年，为中国历史上在位最久的帝王。少年即智擒鳌拜、亲政掌权。平三藩、收台湾、三征噶尔丹、抗击沙俄（签订《尼布楚条约》），文治武功卓著。开博学鸿词科、编纂《康熙字典》《全唐诗》，开创「康乾盛世」。晚年倦政，九子夺嫡，朝局动荡。",
        "yin-zhen": "胤禛（1678—1735年），清世宗（雍正帝），康熙帝第四子。在位十三年，勤政之极，每日批阅奏折数千言。推行「摊丁入亩」「火耗归公」「改土归流」「设立军机处」等重大改革，整顿吏治、充实国库，承上启下，为乾隆盛世奠基。即位过程有篡位疑云，大兴文字狱，杀戮兄弟，争议颇多。",
        "hong-li": "弘历（1711—1799年），清高宗（乾隆帝），雍正帝第四子。在位六十年，康乾盛世达到鼎盛。平定准噶尔、回疆，十全武功，版图辽阔。编纂《四库全书》为中国最大丛书。然后期好大喜功、奢靡浪费，宠信和珅，吏治败坏，白莲教起义此起彼伏。退位后仍掌权三年，清朝由盛转衰。",
        "lin-ze-xu": "林则徐（1785—1850年），字元抚，福建侯官人，清朝大臣，民族英雄。1839年奉旨赴广东禁烟，于虎门海滩公开销毁鸦片两万余箱，史称「虎门销烟」，由此引发鸦片战争。林则徐是近代中国「睁眼看世界」的第一人，主持翻译《四洲志》，介绍西方地理、政治。后被革职发配伊犁，仍心系国事。",
        "qi-shan": "琦善（1790—1854年），博尔济吉特氏，满洲正黄旗人，清朝大臣。鸦片战争期间接替林则徐为钦差大臣，擅自与英方谈判，答应割让香港，后被革职锁拿。其卖国行径成为近代史上的反面典型，然近年学界对其有重新评价。",
        "hong-xiu-quan": "洪秀全（1814—1864年），广东花县人，太平天国领袖。屡试不第，创立拜上帝教，1851年于金田起义，建太平天国，定都天京（南京），占据半壁江山。颁布《天朝田亩制度》，推行男女平等、废除私产。然定都后内讧不断（天京事变），后期荒淫腐朽。1864年天京陷落前夕病逝，太平天国覆灭。",
        "zeng-guo-fan": "曾国藩（1811—1872年），字伯涵，号涤生，湖南湘乡人，晚清中兴名臣之首。创建湘军，历时十余年平定太平天国，挽清朝于倾覆。倡导洋务运动，建安庆内军械所、派遣留学生。一生以理学修身，治军严明，家书教育后人，影响深远。然处理天津教案手段软弱，备受争议。",
        "li-hong-zhang": "李鸿章（1823—1901年），字少荃，安徽合肥人，晚清重臣，洋务运动领袖。曾国藩弟子，创建淮军，参与平定太平天国与捻军。主导洋务运动，创办江南制造局、轮船招商局、北洋水师等。然甲午战败，北洋水师覆灭，代表清廷签订《马关条约》《辛丑条约》等丧权辱国之约，背负「卖国」骂名。梁启超评其「敬其才、惜其识、悲其遇」。",
        "zuo-zong-tang": "左宗棠（1812—1885年），字季高，湖南湘阴人，晚清中兴名臣。举人出身，才华横溢。参与平定太平天国，后力排众议、抬棺出征，收复新疆一百六十余万平方公里国土，维护国家领土完整，功勋卓著。又创办福州船政局，为洋务运动重要人物。",
        "guang-xu-di": "载湉（1871—1908年），清德宗（光绪帝），醇亲王奕譞之子。1875年入继大统，1889年亲政。甲午战败后深受刺激，1898年支持康有为、梁启超推行「戊戌变法」（百日维新），仅一百零三天即被慈禧太后发动政变推翻。此后被幽禁于瀛台十年，郁郁而终（疑被毒杀）。",
        "ci-xi": "慈禧太后（1835—1908年），叶赫那拉氏，咸丰帝贵妃，晚清实际统治者。1861年辛酉政变后垂帘听政，此后三次垂帘、两度训政，掌控清朝政权近半个世纪。期间签订《马关条约》《辛丑条约》等，割地赔款；镇压戊戌变法，囚禁光绪帝。亦支持洋务运动、新政改革，但总体上维护专制、阻碍进步，是近代中国落后挨打的重要责任人。",
        "kang-you-wei": "康有为（1858—1927年），字广厦，号长素，广东南海人，戊戌变法领袖。1895年「公车上书」反对《马关条约》，主张变法图强。1898年推动「百日维新」，倡导君主立宪、兴学校、废八股。变法失败后流亡海外，组织保皇会。晚年参与张勋复辟，思想日趋保守。著有《新学伪经考》《孔子改制考》。",
        "liang-qi-chao": "梁启超（1873—1929年），字卓如，号任公，广东新会人，戊戌变法领袖之一，近代杰出学者、政治家。康有为弟子，师徒并称「康梁」。变法失败后流亡日本，创办《新民丛报》，倡导「新民说」，介绍西方思想。民国后历任司法总长、财政总长，晚年任教清华国学研究院。其文章气势磅礴、感情充沛，号「新文体」，影响一代青年。",
        "tan-si-tong": "谭嗣同（1865—1898年），字复生，号壮飞，湖南浏阳人，戊戌六君子之一。著《仁学》，批判专制、倡导变法。1898年参与戊戌变法，变法失败后拒绝逃走，曰：「各国变法，无不从流血而成，今中国未闻有因变法而流血者，此国之所以不昌也。有之，请自嗣同始！」从容就义，年仅三十三。其慷慨赴死的精神激励后世无数志士。",
        "sun-zhong-shan": "孙中山（1866—1925年），名文，字逸仙，号中山，广东香山人，中国近代民主革命先驱，中华民国国父。创立兴中会、同盟会，提出「驱除鞑虏、恢复中华、创立合众政府」。领导多次武装起义，1911年辛亥革命推翻清朝，建立中华民国。提出「三民主义」（民族、民权、民生），1924年改组国民党、实行联俄联共。1925年病逝于北京，遗言「革命尚未成功，同志仍须努力」。",
        "yuan-shi-kai": "袁世凯（1859—1916年），字慰亭，号容庵，河南项城人，北洋军阀领袖。小站练兵起家，戊戌变法中出卖维新派。辛亥革命后逼清帝退位，任中华民国临时大总统，后改为终身大总统。1915年悍然称帝，改国号「中华帝国」，遭全国声讨，被迫取消帝制，83天后忧愤而死。其复辟倒行逆施，使中国陷入军阀混战。",
        "pu-yi": "溥仪（1906—1967年），爱新觉罗氏，清朝末代皇帝。三岁即位，六岁退位（1912年）。1917年张勋复辟，溥仪再次登基仅十二天。1932年被日本扶植为伪满洲国傀儡皇帝。1945年被苏军俘虏，1950年移交中国，1959年获特赦。晚年著《我的前半生》，成为普通公民。一生经历帝制、民国、伪满、新中国，是中国近代史的缩影。",
    },
)

# ── 五代十国 ──────────────────────────────────────────────────────────────────
enrich(
    "wu-dai-shi-guo.json",
    person_content={
        "zhu-wen-wd": "朱温（852—912年），宋州砀山人，后梁开国皇帝（梁太祖）。原为黄巢部将，降唐赐名全忠，据宣武镇渐成最强藩镇。挟天子、诛朝臣，907年代唐建后梁，开五代之局。在位有抑制藩镇、奖励农桑之举，然性残暴多疑，骨肉相残，终为子朱友珪所弑，后梁国祚短促。",
        "li-cun-xu": "李存勖（885—926年），沙陀族，后唐开国皇帝（唐庄宗）。其父李克用与朱温世仇。存勖骁勇善战、用兵如神，灭后梁、定河北，又取前蜀，武功极盛，一度有统一之势。然得国后宠伶人、疏功臣、纵皇后干政，骄奢失政，兴教门之变中为乱兵所杀，「忧劳可以兴国，逸豫可以亡身」之叹由此而发。",
        "shi-jing-tang": "石敬瑭（892—942年），沙陀族，后晋开国皇帝（晋高祖）。原为后唐重将，936年为夺帝位，向契丹称臣称子，割让燕云十六州、岁输绢帛，借契丹兵灭后唐而立后晋，自称「儿皇帝」。燕云之失使中原失去北方屏障，影响此后四百年中原王朝的边防格局，为后世所唾骂。",
        "guo-wei": "郭威（904—954年），邢州尧山人，后周开国皇帝（周太祖）。出身寒微，行伍起家，为后汉重臣。951年因受猜忌起兵，代汉建后周。在位轻徭薄赋、惩贪倡廉、整顿弊政、与民休息，为后周强盛与日后统一奠定基础，是五代中难得勤俭爱民的君主。无子，传位养子柴荣。",
        "chai-rong": "柴荣（921—959年），邢州尧山人，郭威养子，后周第二位皇帝（周世宗），五代第一明君。即位后励精图治、整军经武、招抚流亡、均定田赋，又西败后蜀、南取南唐江北、北伐契丹连复三州。立志「以十年开拓天下，十年养百姓，十年致太平」，惜壮志未酬、英年早逝，所积基业为赵匡胤所承，开北宋统一之局。",
        "zhao-kuang-yin": "赵匡胤（927—976年），涿州人，北宋开国皇帝（宋太祖）。后周禁军统帅，屡立战功。960年陈桥兵变、黄袍加身，代周建宋。即位后行「杯酒释兵权」，收兵权于中央，确立崇文抑武、强干弱枝之策。先南后北，次第削平诸国，结束五代十国分裂，奠定北宋一统与文治格局。",
        "li-yu": "李煜（937—978年），字重光，南唐后主，五代最杰出的词人。精书画、通音律、工诗文。在位时南唐已奉宋为正朔，975年金陵城破、肉袒出降，被掳至汴京封违命侯，受尽屈辱。亡国后词风骤变，由前期的绮丽宫词转为深沉哀婉、血泪交融，《虞美人》《浪淘沙》《相见欢》境界深远，被誉为「词中之帝」。",
        "qian-liu": "钱镠（852—932年），杭州临安人，吴越国建立者（吴越武肃王）。唐末镇压农民军起家，据有两浙。立国后奉中原王朝为正朔、不称帝，保境安民、休兵息民，大兴水利、修筑钱塘江海塘（捍海石塘），兴修苏杭，使两浙免于战乱、富庶安定。其子孙遵「善事中国」遗训，后纳土归宋，泽被东南。",
        "meng-zhi-xiang": "孟知祥（874—934年），邢州龙冈人，后蜀建立者（蜀高祖）。后唐重臣，受命镇守西川。后唐内乱之际据蜀自立，934年称帝，建后蜀，割据四川。蜀地险固、物产丰饶，后蜀偏安一隅，文教颇盛，至其子孟昶时尤以奢靡与词章著称。",
        "liu-yan": "刘岩（889—942年），又名刘龑，彭城人（生于岭南），南汉建立者（汉高祖）。其兄刘隐据有岭南，岩继之，917年称帝，建南汉，定都广州（兴王府）。据有两广，开科取士、兴海外贸易，岭南一时富庶。然性奢侈残忍，多用酷刑，又信用宦官，为南汉日后积弊埋下隐患。",
    },
)

# ── 元朝 ──────────────────────────────────────────────────────────────────────
enrich(
    "yuan.json",
    person_content={
        "hu-bi-lie-yuan": "忽必烈（1215—1294年），成吉思汗之孙，拖雷之子，元朝开国皇帝（元世祖）。1260年即大汗位，1271年改国号为大元，定都大都（北京）。1279年灭南宋，统一全国，结束自唐末以来数百年的分裂。在位推行汉法、建立行省制度、开通大运河、发展海外贸易。然征日本、征安南等远征劳民伤财，晚年政局渐衰。",
        "cheng-ji-si-han-yuan": "成吉思汗（1162—1227年），名铁木真，蒙古乞颜部人，蒙古帝国创建者。统一蒙古各部，1206年被推为大汗。此后发动大规模西征，征服中亚、西亚、东欧大片领土，建立横跨欧亚的庞大帝国。其军事才能和征服伟业改变了世界历史进程，但也伴随着巨大的杀戮和破坏。1227年灭西夏途中病逝。",
        "wo-kuo-tai": "窝阔台（1186—1241年），成吉思汗第三子，蒙古帝国第二位大汗。继承父业，灭金国（1234年），继续西征欧洲，兵至匈牙利、波兰。在位期间建和林城、设驿站、定税制，蒙古帝国版图进一步扩大。性嗜酒，1241年酗酒暴亡。",
        "meng-ge": "蒙哥（1209—1259年），成吉思汗之孙，拖雷长子，蒙古帝国第四位大汗。即位后命弟忽必烈征大理、旭烈兀征西亚（灭阿拔斯王朝）。1258年亲率大军攻宋，围攻钓鱼城，1259年于城下病死（一说中炮石伤重），蒙古西征因此中止，南宋得以延续二十年。",
        "bo-yan": "伯颜（1236—1295年），蒙古八邻部人，元朝名将。1274年任灭宋统帅，率大军南下，势如破竹，1276年攻占临安，俘虏宋恭帝及谢太后，南宋基本灭亡。后又平定昔里吉叛乱，为忽必烈朝最重要的军事统帅。善用兵、有谋略，为元朝统一立下首功。",
        "a-he-ma": "阿合马（？—1282年），回回人（色目人），元朝权臣，主管财政。以善于理财获忽必烈信任，任中书平章政事长达二十年。推行官营专卖、增加赋税，虽充实国库，但横征暴敛、卖官鬻爵，激起民愤。1282年被千户王著等人刺杀，死后抄家，其罪行昭彰。",
        "sang-ge": "桑哥（？—1291年），畏兀儿人，元朝权臣，继阿合马之后主管财政。以善于敛财获忽必烈重用，任尚书省平章政事。推行至元钞、清查财政，手段苛酷，大肆搜刮。1291年被弹劾处死，抄家时财产惊人。",
        "ma-ke-bo-luo": "马可·波罗（1254—1324年），威尼斯人，中世纪最著名的旅行家。1271年随父叔东行，经丝绸之路抵达元朝，在中国生活十七年，深得忽必烈信任，曾出任地方官。1295年返回威尼斯，口述《马可·波罗游记》，详细描述东方的繁华富庶，激发欧洲人对东方的向往，对大航海时代有深远影响。",
        "guan-han-qing": "关汉卿（约1220—约1300年），号已斋叟，大都人，元代最伟大的杂剧作家，「元曲四大家」之首。一生创作杂剧六十余种，现存十八种，代表作《窦娥冤》《救风尘》《望江亭》《拜月亭》等。作品深刻反映社会现实，揭露黑暗、同情弱者，人物生动、语言质朴。1958年被世界和平理事会列为世界文化名人。",
        "zheng-si-xiao": "赵孟頫（1254—1322年），字子昂，号松雪道人，湖州人，元代最杰出的书画家。宋朝宗室，出仕元朝，官至翰林学士承旨。书法诸体皆工，楷书尤精，与欧阳询、颜真卿、柳公权并称「楷书四大家」。绘画开创元代文人画新风，诗文亦佳。其书画艺术对后世影响极为深远。",
        "guo-shou-jing": "郭守敬（1231—1316年），字若思，邢台人，元代杰出天文学家、数学家、水利学家。编制《授时历》，以365.2425日为一年，精度领先世界三百年（与格里高利历相同）。创制简仪、仰仪等十余种天文仪器，主持全国天文测量（四海测验）。又主持修建通惠河，解决大都漕运问题。",
        "wang-zheng": "王祯（1271—1368年），字伯善，山东东平人，元代农学家。著《王祯农书》三十七卷，分农桑通诀、百谷谱、农器图谱三部分，系统总结农业生产技术，附农器插图三百余幅，是中国古代农学集大成之作，对后世农业发展影响深远。",
        "tuo-tuo": "脱脱（1314—1355年），字大用，蒙古蔑儿乞部人，元末丞相。1344年主持编修《宋史》《辽史》《金史》，为二十四史中的重要部分。两度出任中书右丞相，推行「脱脱更化」，整顿朝政、恢复科举。后遭政敌诬陷，被流放云南，1355年被冤杀。",
        "han-shan-tong": "韩山童（？—1351年），河北栾城人，元末红巾军起义领袖，白莲教首领。以「明王出世」为号召，宣称天下将大乱。1351年与刘福通策划起义，事泄被捕遇害。其子韩林儿后被立为「小明王」，建宋政权。",
        "liu-fu-tong": "刘福通（？—1363年），颍州人，元末红巾军起义领袖。1351年与韩山童同谋起义，韩山童死后率众攻占颍州，迅速壮大。拥立韩林儿为帝，建「宋」政权，国号龙凤。三次北伐大都，震动元廷。后为张士诚部将所败，溺死于安丰。",
        "zhu-yuan-zhang": "朱元璋（1298—1398年），字国瑞，濠州钟离人，明朝开国皇帝（明太祖）。出身赤贫，幼丧父母，曾为皇觉寺僧。元末投红巾军，逐步崛起，击败陈友谅、张士诚等割据势力，1368年于应天（南京）称帝，北伐推翻元朝，统一天下。在位严刑峻法、废除丞相、大兴文字狱，虽恢复经济、澄清吏治，但杀戮功臣之酷烈为历代罕见。",
    },
)

# ── 中华民国 ──────────────────────────────────────────────────────────────────
enrich(
    "zhong-hua-min-guo.json",
    person_content={
        "sun-zhong-shan-mg": "孙中山（1866—1925年），名文，字逸仙，号中山，广东香山人，中国近代民主革命先驱，中华民国国父。创立兴中会、同盟会，提出「驱除鞑虏、恢复中华、创立合众政府」。领导多次武装起义，1911年辛亥革命推翻清朝，建立中华民国。提出「三民主义」（民族、民权、民生），1924年改组国民党、实行联俄联共。1925年病逝于北京，遗言「革命尚未成功，同志仍须努力」。",
        "yuan-shi-kai-mg": "袁世凯（1859—1916年），字慰亭，号容庵，河南项城人，北洋军阀领袖。小站练兵起家，戊戌变法中出卖维新派。辛亥革命后逼清帝退位，任中华民国临时大总统，后改为终身大总统。1915年悍然称帝，改国号「中华帝国」，遭全国声讨，被迫取消帝制，83天后忧愤而死。其复辟倒行逆施，使中国陷入军阀混战。",
        "huang-xing": "黄兴（1874—1916年），字克强，湖南善化人，辛亥革命元勋，与孙中山并称「孙黄」。创建华兴会，参与领导黄花岗起义、武昌起义等多次武装斗争。南京临时政府成立后任陆军总长。一生戎马，屡败屡战，为推翻清朝立下赫赫战功。1916年病逝于上海，年仅四十二。",
        "song-jiao-ren": "宋教仁（1882—1913年），字钝初，号渔父，湖南桃源人，国民党代理理事长。主张议会政治、责任内阁制，领导国民党在1913年国会选举中大获全胜。1913年3月在上海火车站遇刺身亡（幕后主使疑为袁世凯），年仅三十一。其死引发「二次革命」，民国议会政治夭折。",
        "cai-e": "蔡锷（1882—1916年），字松坡，湖南邵阳人，近代著名军事家。辛亥革命时领导昆明起义，任云南都督。1915年袁世凯称帝，蔡锷潜回云南，发起「护国运动」，率军讨袁，迫使袁世凯取消帝制。1916年病逝于日本，年仅三十四，追赠上将军。其与小凤仙的故事广为流传。",
        "duan-qi-rui": "段祺瑞（1865—1936年），字芝泉，安徽合肥人，北洋军阀皖系首领。袁世凯死后掌控北京政府，三造共和（逼清帝退位、反对袁世凯称帝、讨伐张勋复辟）。1924年任临时执政，后失势下野。九一八事变后拒绝日本拉拢，保持民族气节。1936年病逝于上海。",
        "zhang-zuo-lin": "张作霖（1875—1928年），字雨亭，辽宁海城人，奉系军阀首领，人称「东北王」。绿林出身，逐步控制东北三省，成为北洋时期最大的地方势力。两次直奉战争中崛起，一度控制北京政府。1928年北伐军逼近，退回东北途中，被日本关东军炸死于皇姑屯，史称「皇姑屯事件」。",
        "jiang-jie-shi": "蒋介石（1887—1975年），名中正，字介石，浙江奉化人。早年追随孙中山，黄埔军校校长。1926年领导北伐，1928年统一全国。抗日战争期间任盟军中国战区最高统帅，领导全国抗战。1949年国共内战失败后退守台湾，任中华民国总统至1975年病逝。其一生贯穿民国史，功过争议极大。",
        "song-qing-ling": "宋庆龄（1893—1981年），广东文昌人，孙中山夫人。追随孙中山投身革命，孙中山去世后坚持其三大政策。抗日战争期间积极抗日，支持中国共产党。新中国成立后任中央人民政府副主席、中华人民共和国名誉主席。一生致力于妇女儿童事业和国际和平，被誉为「国之瑰宝」。",
        "zhou-en-lai": "周恩来（1898—1976年），字翔宇，浙江绍兴人，中华人民共和国开国总理。早年留法勤工俭学，加入中国共产党。南昌起义领导人之一，长征中支持毛泽东。抗日战争期间主持国共谈判，新中国成立后任总理兼外交部长二十六年。万隆会议提出「和平共处五项原则」，乒乓外交打开中美关系。一生鞠躬尽瘁，被誉为「人民的好总理」。",
        "mao-ze-dong": "毛泽东（1893—1976年），字润之，湖南湘潭人，中国共产党、中国人民解放军、中华人民共和国的主要缔造者。领导秋收起义、建立井冈山根据地、长征、抗日战争、解放战争，1949年建立中华人民共和国。提出「农村包围城市」革命道路，领导中国人民「站起来」。晚年发动文化大革命，造成严重浩劫。1976年病逝于北京。",
        "zhu-de": "朱德（1886—1976年），字玉阶，四川仪陇人，中国人民解放军总司令，开国元帅之首。早年参加辛亥革命、护国战争，后加入中国共产党。与毛泽东会师井冈山，领导红军长征。抗日战争任八路军总指挥，解放战争任解放军总司令。新中国成立后任全国人大常委会委员长，功勋卓著。",
        "liu-shao-qi": "刘少奇（1898—1969年），湖南宁乡人，中华人民共和国第二任国家主席。早年领导工人运动，抗日战争期间主持华中根据地。新中国成立后主持经济建设，提出「新民主主义阶段论」。文化大革命中被打成「叛徒、内奸、工贼」，遭受残酷迫害，1969年含冤病逝。1980年平反昭雪。",
        "deng-xiao-ping": "邓小平（1904—1997年），四川广安人，中国改革开放总设计师。早年参加革命，三落三起。1978年推动改革开放，提出「一国两制」构想，设立经济特区，带领中国人民「富起来」。1992年南巡讲话，推动市场经济改革。1997年病逝于北京，未能亲眼见证香港回归。",
        "lu-xun": "鲁迅（1881—1936年），原名周树人，字豫才，浙江绍兴人，中国现代文学奠基人。弃医从文，以笔为枪，批判国民劣根性。代表作《狂人日记》《阿Q正传》《孔乙己》《祝福》等。杂文辛辣犀利，被誉为「民族魂」。毛泽东称其「中国文化革命的主将」。1936年病逝于上海，万人送葬。",
        "hu-shi": "胡适（1891—1962年），字适之，安徽绩溪人，新文化运动领袖，著名学者。留美归国后倡导白话文运动，发表《文学改良刍议》，开白话文学之先河。历任北大教授、驻美大使、中央研究院院长。主张「大胆假设，小心求证」，学术成就涵盖哲学、文学、史学、教育学。1962年病逝于台北。",
        "cai-yuan-pei": "蔡元培（1868—1940年），字鹤卿，号孑民，浙江绍兴人，近代著名教育家。1917年任北京大学校长，推行「兼容并包、思想自由」的办学方针，聘请陈独秀、胡适、李大钊等新派学者，使北大成为新文化运动的中心。又创设中央研究院，奠定中国现代学术体制。1940年病逝于香港。",
        "zhang-xue-liang": "张学良（1901—2001年），字汉卿，辽宁海城人，张作霖之子，人称「少帅」。1928年东北易帜，归顺南京国民政府。1936年12月12日发动「西安事变」（双十二事变），扣押蒋介石，逼蒋抗日，促成国共第二次合作。此后被蒋介石软禁长达半世纪，直至1990年恢复自由。2001年病逝于美国夏威夷，享年一百零一岁。",
        "yang-hu-cheng": "杨虎城（1893—1949年），陕西蒲城人，西北军将领。1936年与张学良联合发动「西安事变」，扣押蒋介石，逼蒋抗日。事变和平解决后，杨虎城被蒋介石逼令出国「考察」。抗战爆发后回国即遭逮捕，囚禁十二年。1949年国民党败退前夕，被秘密杀害于重庆，年仅五十六。",
    },
)

